'use client';

import * as React from 'react';
import {
  Box,
  Container,
  Stack,
  Typography,
  TextField,
  InputAdornment,
  Tabs,
  Tab,
  Card,
  CardContent,
  CardActions,
  Button,
  Chip,
  Skeleton,
  Alert,
} from '@mui/material';
import SearchRoundedIcon from '@mui/icons-material/SearchRounded';
import ReceiptLongRoundedIcon from '@mui/icons-material/ReceiptLongRounded';
import LayersRoundedIcon from '@mui/icons-material/LayersRounded';
import CreditCardRoundedIcon from '@mui/icons-material/CreditCardRounded';
import PrintRoundedIcon from '@mui/icons-material/PrintRounded';
import ImageRoundedIcon from '@mui/icons-material/ImageRounded';
import StickyNote2RoundedIcon from '@mui/icons-material/StickyNote2Rounded';
import NamecardModal from './components/NamecardModal';
import CheckOutRight from './components/checkoutRight';

type Variant = { name: string; price: number; note?: string };
type Category = 'นามบัตร' | 'Postcard' | 'Print A3/A4' | 'Photo' | 'Sticker Laser' | (string & {});
type Product = {
  id: string;
  name: string;
  cover: string;
  tint: string;
  badge?: 'NEW' | 'HIT';
  category: Category;
  variants: Variant[];
};

const money = (n: number) =>
  new Intl.NumberFormat('th-TH', {
    style: 'currency',
    currency: 'THB',
    maximumFractionDigits: 0,
  }).format(n);

function useDebouncedValue<T>(value: T, ms = 250) {
  const [v, setV] = React.useState(value);
  React.useEffect(() => {
    const t = setTimeout(() => setV(value), ms);
    return () => clearTimeout(t);
  }, [value, ms]);
  return v;
}

export default function SellPage() {
  const [activeCat, setActiveCat] = React.useState<Category | 'ทั้งหมด'>('ทั้งหมด');
  const [q, setQ] = React.useState('');
  const qDebounced = useDebouncedValue(q, 200);

  const [products, setProducts] = React.useState<Product[]>([]);
  const [loading, setLoading] = React.useState(true);
  const [errorMsg, setErrorMsg] = React.useState<string | null>(null);

  //Modal Product

  const [activeProduct, setActiveProduct] = React.useState<Product | null>(null);
  const [openModal, setOpenModal] = React.useState(false);

  //Cart Checking

  const cart = [
    { key: '1', name: 'นามบัตร', variant: 'Portrait', qty: 100, unitPrice: 3, note: 'พิมพ์ด่วน' },
    { key: '2', name: 'สติ๊กเกอร์', variant: 'A5', qty: 10, unitPrice: 20 },
  ];

  const total = cart.reduce((sum, item) => sum + item.unitPrice * item.qty, 0);

  React.useEffect(() => {
    const base = process.env.NEXT_PUBLIC_API_URL ?? '';
    if (!base) {
      setErrorMsg('ยังไม่ได้ตั้งค่า NEXT_PUBLIC_API_URL ใน .env');
      setLoading(false);
      return;
    }
    fetch(`${base}/products`)
      .then(async res => {
        if (!res.ok) throw new Error(`HTTP ${res.status}`);
        const data = (await res.json()) as Product[];
        setProducts(Array.isArray(data) ? data : []);
        setLoading(false);
      })
      .catch(() => {
        setErrorMsg('โหลดสินค้าล้มเหลว กรุณาลองใหม่');
        setLoading(false);
      });
  }, []);

  const categories = React.useMemo(() => {
    const set = new Set<Category>();
    products.forEach(p => set.add(p.category));
    if (activeCat !== 'ทั้งหมด' && !set.has(activeCat)) setActiveCat('ทั้งหมด');
    return Array.from(set);
  }, [products]);

  const filtered = React.useMemo(() => {
    return products
      .filter(p => (activeCat === 'ทั้งหมด' ? true : p.category === activeCat))
      .filter(p => p.name.toLowerCase().includes(qDebounced.toLowerCase()));
  }, [products, activeCat, qDebounced]);

  const catIcon = (cat: Category) => {
    if (cat === 'นามบัตร') return <CreditCardRoundedIcon />;
    if (cat === 'Postcard' || cat === 'Photo') return <ImageRoundedIcon />;
    if (cat === 'Print A3/A4') return <PrintRoundedIcon />;
    if (cat === 'Sticker Laser') return <StickyNote2RoundedIcon />;
    return <LayersRoundedIcon />;
  };

  return (
    <Box sx={{ minHeight: '100dvh' }}>
      <Container maxWidth="xl" sx={{ py: 2 }}>
        {/* Header */}
        <Stack direction="row" alignItems="center" spacing={1} sx={{ mb: 2 }}>
          <ReceiptLongRoundedIcon />
          <Typography variant="h5" color="black" fontWeight={800}>
            หน้าขาย (POS)
          </Typography>
        </Stack>

        {errorMsg && (
          <Alert severity="error" sx={{ mb: 2 }}>
            {errorMsg}
          </Alert>
        )}

        <TextField
          size="small"
          placeholder="ค้นหา…"
          value={q}
          onChange={e => setQ(e.target.value)}
          InputProps={{
            startAdornment: (
              <InputAdornment position="start">
                <SearchRoundedIcon />
              </InputAdornment>
            ),
          }}
          sx={{ minWidth: 750 }}
        />

        <Box sx={{ mt: 2 }}>
          <Tabs
            value={activeCat}
            onChange={(_, v) => setActiveCat(v)}
            variant="scrollable"
            allowScrollButtonsMobile
            sx={{
              mb: 2,
              '& .MuiTabs-indicator': { height: 3 },
            }}>
            <Tab
              value="ทั้งหมด"
              icon={<LayersRoundedIcon />}
              iconPosition="start"
              label="ทั้งหมด"
            />
            {categories.map(c => (
              <Tab key={c} value={c} icon={catIcon(c)} iconPosition="start" label={c} />
            ))}
          </Tabs>

          <Box sx={{ display: 'flex', flexWrap: 'wrap', gap: 2 }}>
            {loading &&
              Array.from({ length: 8 }).map((_, i) => (
                <Card
                  key={`sk-${i}`}
                  variant="outlined"
                  sx={{
                    width: { xs: 'calc(50% - 8px)', sm: 260, md: 280 },
                    borderRadius: 3,
                    overflow: 'hidden',
                  }}>
                  <Skeleton variant="rectangular" width="100%" height={120} />
                  <CardContent>
                    <Skeleton width="80%" />
                    <Skeleton width="40%" />
                  </CardContent>
                  <CardActions sx={{ p: 1.5, pt: 0.5 }}>
                    <Skeleton variant="rectangular" width="100%" height={36} />
                  </CardActions>
                </Card>
              ))}

            {!loading && filtered.length === 0 && (
              <Box p={4} width="100%" textAlign="center" color="text.secondary">
                <Typography>ไม่พบสินค้าในหมวดนี้ / คำค้นนี้</Typography>
              </Box>
            )}

            

            {!loading &&
              filtered.map(p => (
                <Card
                  key={p.id}
                  variant="outlined"
                  sx={{
                    width: { xs: 'calc(50% - 8px)', sm: 260, md: 280 },
                    borderRadius: 3,
                    overflow: 'hidden',
                    backdropFilter: 'blur(4px)',
                    boxShadow: '0 6px 24px rgba(0,0,0,.06)',
                    '&:hover': {
                      boxShadow: '0 10px 28px rgba(0,0,0,.1)',
                      transform: 'translateY(-1px)',
                    },
                    transition: 'all .2s',
                  }}>
                  <Box
                    sx={{
                      height: 120,
                      bgcolor: p.tint || '#f5f5f5',
                      display: 'grid',
                      placeItems: 'center',
                      fontSize: 56,
                    }}>
                    {p.cover}
                  </Box>
                  

                  

                  <CardContent sx={{ pb: 0.5 }}>
                    <Stack direction="row" alignItems="center" spacing={1}>
                      <Typography fontWeight={700} flex={1} noWrap>
                        {p.name}
                      </Typography>
                      {p.badge && (
                        <Chip
                          size="small"
                          label={p.badge}
                          color={p.badge === 'NEW' ? 'secondary' : 'primary'}
                        />
                      )}
                    </Stack>
                    <Typography variant="body2" color="text.secondary">
                      {money(p.variants[0].price)}
                    </Typography>
                  </CardContent>
                  <CardActions sx={{ p: 1.5, pt: 0.5 }}>
                    <Button
                      fullWidth
                      variant="contained"
                      onClick={() => {
                        setActiveProduct(p);
                        setOpenModal(true);
                      }}>
                      เพิ่มรายการ
                    </Button>
                  </CardActions>
                </Card>
              ))}

          </Box>
        </Box>
      </Container>

      {/* Modal สำหรับสินค้าประเภทนามบัตร */}
      {activeProduct?.category === 'นามบัตร' && (
        <NamecardModal
          open={openModal}
          onClose={() => setOpenModal(false)}
          productName={activeProduct.name}
          onSelect={order => {
            console.log('สั่งนามบัตร:', order);
            setOpenModal(false);
          }}
        />
      )}
    </Box>
  );
}
